"""
Parameterized generator for GH163_psycopg_1223.

Source PR:    https://github.com/psycopg/psycopg/pull/1223
Source Issue: N/A

Seed varies: renames 'action' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH163_psycopg_1223'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH163_psycopg_1223'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('action', 'action' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH163_psycopg_1223',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'psycopg/psycopg',
                "pr_number": 1223,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/psycopg/psycopg/pull/1223",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            '.github/workflows/3rd-party-tests.yml': 'name: 3rd party tests\n\non:\n  push:\n    branches:\n      - "master"\n      - "maint-3.1"\n      - "maint-3.2"\n      - "sqlalchemy_pipeline"\n      - "django_pipeline"\n    paths-ignore:\n      - "docs/*"\n      - "tools/*"\n  workflow_dispatch:\n\nconcurrency:\n  # Cancel older requests of the same workflow in the same branch.\n  group: ${{ github.workflow }}-${{ github.ref_name }}\n  cancel-in-progress: true\n\njobs:\n  sqlalchemy:\n    # linux should be enough to test if everything works.\n    runs-on: ubuntu-latest\n    if: true\n    strategy:\n      fail-fast: false\n      matrix:\n        python-version:\n          - "3.13"\n          - "3.10"\n        sqlalchemy_label:\n          # what version of sqlalchemy to download is defined in the "include" section below,\n          # in the variable pip_sqlalchemy\n          - git_main\n          - release\n        impl:\n          - c\n          - python\n        include:\n          - sqlalchemy_label: git_main\n            pip_sqlalchemy: git+https://github.com/sqlalchemy/sqlalchemy.git#egg=sqlalchemy\n          - sqlalchemy_label: release\n            pip_sqlalchemy: sqlalchemy>=2\n\n    env:\n      PSYCOPG_IMPL: ${{ matrix.impl }}\n      DEPS: ./psycopg pytest pytest-xdist greenlet\n\n    services:\n      postgresql:\n        image: postgres:15\n        env:\n          POSTGRES_PASSWORD: password\n          POSTGRES_DB: test\n        ports:\n          - 5432:5432\n        # Wait until postgres has started\n        options: >-\n          --health-cmd pg_isready\n          --health-interval 10s\n          --health-timeout 5s\n          --health-retries 5\n\n    steps:\n      - uses: actions/checkout@v5\n\n      - uses: actions/setup-python@v6\n        with:\n          python-version: ${{ matrix.python-version }}\n\n      - name: Setup PG\n        env:\n          PGPASSWORD: password\n        run: |\n          psql -AXqte "host=127.0.0.1 dbname=test user=postgres" << HERE\n          SELECT version();\n          CREATE SCHEMA test_schema;\n          CREATE SCHEMA test_schema_2;\n          CREATE EXTENSION hstore;\n          HERE\n\n      - name: Include psycopg-c to the packages to install\n        if: ${{ matrix.impl == \'c\' }}\n        run: |\n          echo "DEPS=$DEPS ./psycopg_c" >> $GITHUB_ENV\n\n      - name: Install pycopg packages\n        run: pip install $DEPS\n\n      - name: Setup and install sqlalchemy\n        run: |\n          pip download --no-deps --no-binary :all: ${{ matrix.pip_sqlalchemy }}\n          mkdir sa_home\n          case $(file --brief --mime-type sqlalchemy*) in\n            application/gzip)\n              tar -C sa_home -xzf sqlalchemy*\n              ;;\n            application/zip)\n              unzip -d sa_home -q sqlalchemy*\n              ;;\n            *)\n              echo "Unexpected format for $(file --mime-type sqlalchemy*)" >&2\n              exit 1\n              ;;\n          esac\n          mv sa_home/$( ls sa_home ) sa_home/sa\n          cd sa_home/sa\n          pip install .\n\n      - name: Run sqlalchemy tests\n        env:\n          URL: postgresql+psycopg://postgres:password@127.0.0.1/test\n        working-directory: sa_home/sa\n        run: pytest -n 2 -q --dburi $URL --backend-only --dropfirst --color=yes --dbdriver psycopg_async\n\n  django:\n    # linux should be enough to test if everything works.\n    runs-on: ubuntu-latest\n    if: true\n    strategy:\n      fail-fast: false\n      matrix:\n        django_label:\n          # what version of django to download is defined in the "include"\n          # section below, in the variable pip_django\n          - git_main\n          - lts4\n          - lts5\n        impl:\n          - c\n          - python\n        include:\n          - django_label: git_main\n            pip_django: git+https://github.com/django/django.git#egg=Django\n          - django_label: lts4\n            pip_django: "\'Django >= 4.2, < 4.3\'"\n            default_auto_fields: \'DEFAULT_AUTO_FIELD = "django.db.models.AutoField"\'\n          - django_label: lts5\n            pip_django: "\'Django >= 5.2, < 5.3\'"\n            default_auto_fields: \'DEFAULT_AUTO_FIELD = "django.db.models.AutoField"\'\n\n          # Test with min and max Python supported versions\n          - django_label: lts4\n            impl: c\n            python-version: "3.11"\n          - django_label: lts4\n            impl: python\n            python-version: "3.12"\n          - django_label: lts5\n            impl: c\n            python-version: "3.10"\n          - django_label: lts5\n            impl: python\n            python-version: "3.13"\n          - django_label: git_main\n            impl: c\n            python-version: "3.13"\n          - django_label: git_main\n            impl: python\n            python-version: "3.12"\n\n    env:\n      DEPS: ./psycopg ./psycopg_pool\n\n    services:\n      postgresql:\n        image: postgres:15\n        env:\n          POSTGRES_PASSWORD: password\n          POSTGRES_DB: postgres\n        ports:\n          - 5432:5432\n        # Wait until postgres has started\n        options: >-\n          --health-cmd pg_isready\n          --health-interval 10s\n          --health-timeout 5s\n          --health-retries 5\n\n    steps:\n      - uses: actions/checkout@v5\n\n      - uses: actions/setup-python@v6\n        with:\n          python-version: ${{ matrix.python-version }}\n\n      - name: Setup PG\n        env:\n          PGPASSWORD: password\n        run: |\n          psql -AXqte "host=127.0.0.1 dbname=postgres user=postgres" << HERE\n          SELECT version();\n          HERE\n\n      - name: Include psycopg-c to the packages to install\n        if: ${{ matrix.impl == \'c\' }}\n        run: |\n          echo "DEPS=$DEPS ./psycopg_c" >> $GITHUB_ENV\n\n      - name: Install pycopg packages\n        run: pip install $DEPS\n\n      - name: Download and configure Django\n        run: |\n          pip download --no-deps --no-binary :all: ${{ matrix.pip_django }}\n          mkdir workdir\n          case $(file --brief --mime-type [Dd]jango*) in\n            application/gzip)\n              tar -C workdir -xzf [Dd]jango*\n              ;;\n            application/zip)\n              unzip -d workdir -q [Dd]jango*\n              ;;\n            *)\n              echo "Unexpected format for $(file --mime-type [Dd]jango*)" >&2\n              exit 1\n              ;;\n          esac\n          mv workdir/$( ls workdir ) workdir/django\n          cat << HERE > workdir/django/tests/test_postgresql.py\n          DATABASES = {\n              "default": {\n                  "ENGINE": "django.db.backends.postgresql",\n                  "HOST": "127.0.0.1",\n                  "USER": "postgres",\n                  "PASSWORD": "password",\n              },\n              "other": {\n                  "ENGINE": "django.db.backends.postgresql",\n                  "HOST": "127.0.0.1",\n                  "USER": "postgres",\n                  "PASSWORD": "password",\n              },\n          }\n\n          SECRET_KEY = "django_tests_secret_key"\n\n          # Use a fast hasher to speed up tests.\n          PASSWORD_HASHERS = [\n              "django.contrib.auth.hashers.MD5PasswordHasher",\n          ]\n\n          ${{ matrix.default_auto_fields }}\n          USE_TZ = False\n          HERE\n\n      - uses: actions/cache@v4\n        with:\n          path: ~/.cache/pip\n          key: ${{ matrix.python-version }}-pip-${{ hashFiles(\'workdir/django/tests/requirements/py3.txt\', \'workdir/django/setup.cfg\') }}\n          restore-keys: |\n            ${{ matrix.python-version }}-pip-\n\n      - name: Install Django and dependencies\n        working-directory: workdir/django\n        run: |\n          # pylibmc wheel package not available from Python 3.12.\n          # https://github.com/lericson/pylibmc/issues/288\n          # Dependency in:\n          # https://github.com/django/django/blob/main/tests/requirements/py3.txt#L12\n          # (You can check the above in case it gets dropped in the future).\n          sudo apt-get install -y libmemcached-dev\n          pip install .\n          pip install -r tests/requirements/py3.txt\n\n      - name: Run Django tests\n        working-directory: workdir/django/tests\n        run: ./runtests.py --settings=test_postgresql postgres_tests backends queries\n',
            '.github/workflows/build-and-cache-libpq.yml': 'name: Build and cache libpq\n\n# Build the libpq package and cache the artifacts.\n#\n# Every Python version on the same architecture will use the same libpq.\n# Therefore building and caching the libpq together with the binary packages\n# result in multiple concurrent builds, and the github artifacts manageer very\n# confused.\n#\n# This job builds the libpq and then caches the artifacts so that the\n# packages-bin.yml workflow will find the library in the cache.\n#\n# You can see the caches at https://github.com/psycopg/psycopg/actions/caches\n#\n# Or from the API:\n#\n#   curl -fsSL -X GET \\\n#     -H "Accept: application/vnd.github+json" \\\n#     -H "Authorization: Bearer $GITHUB_TOKEN" \\\n#     -H "X-GitHub-Api-Version: 2022-11-28" \\\n#     "https://api.github.com/repos/psycopg/psycopg/actions/caches" \\\n#   | jq -r \'.actions_caches[].key\'\n#\n# You can delete a cache using:\n#\n#   curl -fsSL -X DELETE \\\n#     -H "Accept: application/vnd.github+json" \\\n#     -H "Authorization: Bearer $GITHUB_TOKEN" \\\n#     -H "X-GitHub-Api-Version: 2022-11-28" \\\n#     "https://api.github.com/repos/psycopg/psycopg/actions/caches?key=libpq-manylinux-ppc64le-17.2-3.4.0"\n#\n# ref: https://docs.github.com/en/rest/actions/cache?apiVersion=2022-11-28#delete-github-actions-caches-for-a-repository-using-a-cache-key\n\non:\n  workflow_dispatch:\n  push:\n    paths:\n      - .github/workflows/build-and-cache-libpq.yml\n\n# TODO: move these env vars in an external env file in order to share them\n# across workflows.\n\nenv:\n  # Latest release: https://www.postgresql.org/ftp/source/\n  LIBPQ_VERSION: "18.0"\n  # Note: On windows the latest version can be found at\n  # https://vcpkg.io/en/package/libpq\n  # However the command line tool doesn\'t have a flag to specify to install\n  # a specific version, so whatever you get you keep it.\n  # https://github.com/microsoft/vcpkg/discussions/25622\n\n  # Latest release: https://www.openssl.org/source/\n  OPENSSL_VERSION: "3.5.4"\n\n  # A string to differentiate build cacke keys to allow building different\n  # flavours of libpq in different branches without mixups. Currently used to\n  # make sure that libpq packages built for Psycopg 3.2 and 3.3 don\'t mix (in\n  # order to change the gssencmode default only on 3.3). We may use it for\n  # different reasons in the future.\n  PQ_FLAGS: "-gssencmode-disable"\n\nconcurrency:\n  # Cancel older requests of the same workflow in the same branch.\n  group: ${{ github.workflow }}-${{ github.ref_name }}\n  cancel-in-progress: true\n\njobs:\n\n  linux:  # {{{\n    runs-on: ubuntu-latest\n    if: true\n\n    strategy:\n      fail-fast: false\n      matrix:\n        arch: [x86_64, ppc64le, aarch64, riscv64]\n        platform: [manylinux, musllinux]\n\n    steps:\n      - uses: actions/checkout@v5\n\n      - name: Set up QEMU for multi-arch build\n        # Check https://github.com/docker/setup-qemu-action for newer versions.\n        uses: docker/setup-qemu-action@v3\n        with:\n          # https://github.com/pypa/cibuildwheel/discussions/2256\n          image: tonistiigi/binfmt:qemu-v8.1.5\n\n      - name: Cache libpq build\n        uses: actions/cache@v4\n        with:\n          path: /tmp/libpq.build\n          key: libpq-${{ matrix.platform }}-${{ matrix.arch }}-${{ env.LIBPQ_VERSION }}-${{ env.OPENSSL_VERSION }}${{ env.PQ_FLAGS }}\n\n      - name: Build wheels\n        uses: pypa/cibuildwheel@v3.2.1\n        with:\n          package-dir: psycopg_c\n        env:\n          CIBW_MANYLINUX_X86_64_IMAGE: manylinux2014\n          CIBW_MANYLINUX_I686_IMAGE: manylinux2014\n          CIBW_MANYLINUX_AARCH64_IMAGE: manylinux_2_28\n          CIBW_MANYLINUX_PPC64LE_IMAGE: manylinux2014\n          CIBW_MANYLINUX_RISCV64_IMAGE: quay.io/pypa/manylinux_2_39_riscv64\n          CIBW_BUILD: cp313-${{matrix.platform}}_${{matrix.arch}}\n          CIBW_ARCHS_LINUX: auto aarch64 ppc64le riscv64\n          CIBW_BEFORE_ALL_LINUX: ./tools/ci/build_libpq.sh\n          CIBW_REPAIR_WHEEL_COMMAND: >-\n            ./tools/ci/strip_wheel.sh {wheel}\n            && auditwheel repair -w {dest_dir} {wheel}\n          CIBW_ENVIRONMENT_PASS_LINUX: LIBPQ_VERSION OPENSSL_VERSION\n          CIBW_ENVIRONMENT: >-\n            LIBPQ_BUILD_PREFIX=/host/tmp/libpq.build\n            PATH="$LIBPQ_BUILD_PREFIX/bin:$PATH"\n            LD_LIBRARY_PATH="$LIBPQ_BUILD_PREFIX/lib:$LIBPQ_BUILD_PREFIX/lib64"\n\n\n  # }}}\n\n  macos:  # {{{\n    runs-on: macos-latest\n    if: true\n\n    strategy:\n      fail-fast: false\n      matrix:\n        arch: [x86_64, arm64]\n\n    steps:\n      - name: Checkout repos\n        uses: actions/checkout@v5\n\n      - name: Cache libpq build\n        uses: actions/cache@v4\n        with:\n          path: /tmp/libpq.build\n          key: libpq-macos-${{ env.LIBPQ_VERSION }}-${{ matrix.arch }}-${{ env.OPENSSL_VERSION }}${{ env.PQ_FLAGS }}\n\n      - name: Build wheels\n        uses: pypa/cibuildwheel@v3.2.1\n        with:\n          package-dir: psycopg_c\n        env:\n          CIBW_BUILD: cp313-macosx_${{matrix.arch}}\n          CIBW_ARCHS_MACOS: ${{matrix.arch}}\n          MACOSX_ARCHITECTURE: ${{matrix.arch}}\n          CIBW_BEFORE_ALL_MACOS: ./tools/ci/build_libpq.sh\n          CIBW_ENVIRONMENT: >-\n            PSYCOPG_IMPL=binary\n            LIBPQ_BUILD_PREFIX=/tmp/libpq.build\n            PATH="$LIBPQ_BUILD_PREFIX/bin:$PATH"\n\n  # }}}\n',
            '.github/workflows/lint.yml': 'name: Lint\n\non:\n  push:\n    # This should disable running the workflow on tags, according to the\n    # on.<push|pull_request>.<branches|tags> GitHub Actions docs.\n    branches:\n      - "**"\n  pull_request:\n  schedule:\n    - cron: \'18 6 * * *\'\n\nconcurrency:\n  group: ${{ github.workflow }}-${{ github.ref_name }}\n  cancel-in-progress: true\n\njobs:\n  lint:\n    runs-on: ubuntu-latest\n    if: true\n\n    steps:\n      - uses: actions/checkout@v5\n\n      - uses: actions/setup-python@v6\n        with:\n          python-version: "3.11"\n\n      - name: install packages to tests\n        run: pip install ./psycopg[dev,test]\n\n      - name: Lint codebase\n        run: pre-commit run -a --color=always\n\n      - name: Check for sync/async inconsistencies\n        run: ./tools/async_to_sync.py --check --all\n\n      - name: Install requirements to generate docs\n        run: sudo apt-get install -y libgeos-dev\n\n      - name: Install Python packages to generate docs\n        run: pip install ./psycopg[docs] ./psycopg_pool\n\n      - name: Check documentation\n        run: sphinx-build -W -T -b html docs docs/_build/html\n',
            '.github/workflows/packages-bin.yml': 'name: Build binary packages\n\n# Note: these jobs also build and cache the libpq, but, because every Python\n# version will try to build and cache the same libpq instance, there is a race\n# condition and most likely the artifacts manager will refuse to cache.\n#\n# Please run the `build-and-cache-libpq.yml` workflow when the libpq/openssl\n# version change in order to update the cache.\n\non:\n  push:\n    paths:\n      - \'.github/workflows/packages-bin.yml\'\n  workflow_dispatch:\n  schedule:\n    - cron: \'28 7 * * sun\'\n\nenv:\n  # Latest release: https://www.postgresql.org/ftp/source/\n  LIBPQ_VERSION: "18.0"\n  # Note: On windows the latest version can be found at\n  # https://vcpkg.io/en/package/libpq\n  # However the command line tool doesn\'t have a flag to specify to install\n  # a specific version, so whatever you get you keep it.\n  # https://github.com/microsoft/vcpkg/discussions/25622\n\n  # Latest release: https://www.openssl.org/source/\n  OPENSSL_VERSION: "3.5.4"\n\n  # A string to differentiate build cacke keys to allow building different\n  # flavours of libpq in different branches without mixups. Currently used to\n  # make sure that libpq packages built for Psycopg 3.2 and 3.3 don\'t mix (in\n  # order to change the gssencmode default only on 3.3). We may use it for\n  # different reasons in the future.\n  PQ_FLAGS: "-gssencmode-disable"\n\nconcurrency:\n  # Cancel older requests of the same workflow in the same branch.\n  group: ${{ github.workflow }}-${{ github.ref_name }}\n  cancel-in-progress: true\n\njobs:\n\n  linux:  # {{{\n    runs-on: ubuntu-latest\n    if: true\n\n    strategy:\n      fail-fast: false\n      matrix:\n        arch: [x86_64, ppc64le, aarch64, riscv64]\n        pyver: [cp310, cp311, cp312, cp313, cp314]\n        platform: [manylinux, musllinux]\n\n    steps:\n      - uses: actions/checkout@v5\n\n      - name: Set up QEMU for multi-arch build\n        # Check https://github.com/docker/setup-qemu-action for newer versions.\n        uses: docker/setup-qemu-action@v3\n        with:\n          # https://github.com/pypa/cibuildwheel/discussions/2256\n          image: tonistiigi/binfmt:qemu-v8.1.5\n\n      - name: Cache libpq build\n        uses: actions/cache@v4\n        with:\n          path: /tmp/libpq.build\n          key: libpq-${{ matrix.platform }}-${{ matrix.arch }}-${{ env.LIBPQ_VERSION }}-${{ env.OPENSSL_VERSION }}${{ env.PQ_FLAGS }}\n\n      - name: Create the binary package source tree\n        run: python3 ./tools/ci/copy_to_binary.py\n\n      - name: Build wheels\n        uses: pypa/cibuildwheel@v3.2.1\n        with:\n          package-dir: psycopg_binary\n        env:\n          CIBW_MANYLINUX_X86_64_IMAGE: manylinux2014\n          CIBW_MANYLINUX_AARCH64_IMAGE: manylinux_2_28\n          CIBW_MANYLINUX_PPC64LE_IMAGE: manylinux2014\n          CIBW_MANYLINUX_RISCV64_IMAGE: quay.io/pypa/manylinux_2_39_riscv64\n          CIBW_BUILD: ${{matrix.pyver}}-${{matrix.platform}}_${{matrix.arch}}\n          CIBW_ARCHS_LINUX: auto aarch64 ppc64le riscv64\n          CIBW_BEFORE_ALL_LINUX: ./tools/ci/wheel_linux_before_all.sh\n          CIBW_REPAIR_WHEEL_COMMAND: >-\n            ./tools/ci/strip_wheel.sh {wheel}\n            && auditwheel repair -w {dest_dir} {wheel}\n          CIBW_TEST_REQUIRES: ./psycopg[test] ./psycopg_pool\n          CIBW_TEST_COMMAND: pytest {project}/tests\n          CIBW_ENVIRONMENT_PASS_LINUX: LIBPQ_VERSION OPENSSL_VERSION\n          CIBW_ENVIRONMENT: >-\n            PSYCOPG_IMPL=binary\n            PSYCOPG_TEST_DSN=\'host=172.17.0.1 user=postgres\'\n            PGPASSWORD=password\n            LIBPQ_BUILD_PREFIX=/host/tmp/libpq.build\n            PATH="$LIBPQ_BUILD_PREFIX/bin:$PATH"\n            LD_LIBRARY_PATH="$LIBPQ_BUILD_PREFIX/lib:$LIBPQ_BUILD_PREFIX/lib64"\n            PSYCOPG_TEST_WANT_LIBPQ_BUILD=${{ env.LIBPQ_VERSION }}\n            PSYCOPG_TEST_WANT_LIBPQ_IMPORT=${{ env.LIBPQ_VERSION }}\n            PYTEST_ADDOPTS="-m \'not slow and not flakey\' --color yes"\n\n      - uses: actions/upload-artifact@v5\n        with:\n          name: linux-${{matrix.pyver}}-${{matrix.platform}}_${{matrix.arch}}\n          path: ./wheelhouse/*.whl\n\n    services:\n      postgresql:\n        image: postgres:14\n        env:\n          POSTGRES_PASSWORD: password\n        ports:\n          - 5432:5432\n        # Set health checks to wait until postgres has started\n        options: >-\n          --health-cmd pg_isready\n          --health-interval 10s\n          --health-timeout 5s\n          --health-retries 5\n\n\n  # }}}\n\n  macos:  # {{{\n    runs-on: macos-latest\n    if: true\n\n    strategy:\n      fail-fast: false\n      matrix:\n        arch: [x86_64, arm64]\n        pyver: [cp310, cp311, cp312, cp313, cp314]\n\n    steps:\n      - name: Checkout repos\n        uses: actions/checkout@v5\n\n      - name: Cache libpq build\n        uses: actions/cache@v4\n        with:\n          path: /tmp/libpq.build\n          key: libpq-macos-${{ env.LIBPQ_VERSION }}-${{ matrix.arch }}-${{ env.OPENSSL_VERSION }}${{ env.PQ_FLAGS }}\n\n      - name: Create the binary package source tree\n        run: python3 ./tools/ci/copy_to_binary.py\n\n      - name: Build wheels\n        uses: pypa/cibuildwheel@v3.2.1\n        with:\n          package-dir: psycopg_binary\n        env:\n          CIBW_BUILD: ${{matrix.pyver}}-macosx_${{matrix.arch}}\n          CIBW_ARCHS_MACOS: ${{matrix.arch}}\n          MACOSX_ARCHITECTURE: ${{matrix.arch}}\n          CIBW_BEFORE_ALL_MACOS: ./tools/ci/wheel_macos_before_all.sh\n          CIBW_TEST_REQUIRES: ./psycopg[test] ./psycopg_pool\n          CIBW_TEST_COMMAND: pytest {project}/tests\n          CIBW_ENVIRONMENT: >-\n            PG_VERSION=18\n            PSYCOPG_IMPL=binary\n            PSYCOPG_TEST_DSN=\'dbname=postgres\'\n            LIBPQ_BUILD_PREFIX=/tmp/libpq.build\n            PATH="$LIBPQ_BUILD_PREFIX/bin:$PATH"\n            PSYCOPG_TEST_WANT_LIBPQ_BUILD=">= ${{env.LIBPQ_VERSION}}"\n            PSYCOPG_TEST_WANT_LIBPQ_IMPORT=">= ${{env.LIBPQ_VERSION}}"\n            PYTEST_ADDOPTS="-m \'not slow and not flakey and not proxy\' --color yes"\n\n      - name: Upload artifacts\n        uses: actions/upload-artifact@v5\n        with:\n          name: macos-${{matrix.pyver}}-${{matrix.arch}}\n          path: ./wheelhouse/*.whl\n\n\n  # }}}\n\n  windows:  # {{{\n    # TODO: move it back to windows-latest when the default runner switches.\n    runs-on: windows-2025\n    if: true\n\n    strategy:\n      fail-fast: false\n      matrix:\n        arch: [win_amd64]\n        pyver: [cp310, cp311, cp312, cp313, cp314]\n\n    defaults:\n      run:\n        shell: bash\n\n    steps:\n      # there are some other libpq in PATH\n      - run: rm -rf c:/tools/php C:/Strawberry/c/bin\n\n      - uses: actions/checkout@v5\n\n      - name: Start PostgreSQL service for test\n        run: |\n          $PgSvc = Get-Service "postgresql*"\n          Set-Service $PgSvc.Name -StartupType manual\n          $PgSvc.Start()\n        shell: powershell\n\n      - name: Export GitHub Actions cache environment variables\n        uses: actions/github-script@v8\n        with:\n          script: |\n            const path = require(\'path\')\n            core.exportVariable(\'ACTIONS_CACHE_URL\', process.env.ACTIONS_CACHE_URL || \'\');\n            core.exportVariable(\'ACTIONS_RUNTIME_TOKEN\', process.env.ACTIONS_RUNTIME_TOKEN || \'\');\n            core.addPath(path.join(process.env.VCPKG_INSTALLATION_ROOT, \'installed/x64-windows-release/lib\'));\n            core.addPath(path.join(process.env.VCPKG_INSTALLATION_ROOT, \'installed/x64-windows-release/bin\'));\n\n      - name: Create the binary package source tree\n        run: python3 ./tools/ci/copy_to_binary.py\n\n      - name: Build wheels\n        uses: pypa/cibuildwheel@v3.2.1\n        with:\n          package-dir: psycopg_binary\n        env:\n          VCPKG_BINARY_SOURCES: "clear;x-gha,readwrite" # cache vcpkg\n          CIBW_BUILD: ${{matrix.pyver}}-${{matrix.arch}}\n          CIBW_ARCHS_WINDOWS: AMD64 x86\n          CIBW_BEFORE_BUILD_WINDOWS: \'.\\tools\\ci\\wheel_win32_before_build.bat\'\n          CIBW_REPAIR_WHEEL_COMMAND_WINDOWS: >-\n            delvewheel repair -w {dest_dir}\n            --no-mangle "libiconv-2.dll;libwinpthread-1.dll" {wheel}\n          CIBW_TEST_REQUIRES: ./psycopg[test] ./psycopg_pool\n          CIBW_TEST_COMMAND: pytest {project}/tests\n          CIBW_ENVIRONMENT_WINDOWS: >-\n            PSYCOPG_IMPL=binary\n            PSYCOPG_TEST_DSN="host=127.0.0.1 user=postgres"\n            PSYCOPG_TEST_WANT_LIBPQ_BUILD=">= 16"\n            PSYCOPG_TEST_WANT_LIBPQ_IMPORT=">= 16"\n            PYTEST_ADDOPTS="-m \'not slow and not flakey and not proxy\' --color yes"\n\n      - uses: actions/upload-artifact@v5\n        with:\n          name: windows-${{matrix.pyver}}-${{matrix.arch}}\n          path: ./wheelhouse/*.whl\n\n\n  # }}}\n\n  merge:  # {{{\n    runs-on: ubuntu-latest\n    needs:\n      - linux\n      - macos\n      - windows\n    steps:\n      - name: Merge Artifacts\n        uses: actions/upload-artifact/merge@v5\n        with:\n          name: psycopg-binary-artifact\n          delete-merged: true\n\n  # }}}\n',
            '.github/workflows/packages-pool.yml': 'name: Build pool packages\n\non:\n  push:\n    paths:\n      - \'.github/workflows/packages-pool.yml\'\n  workflow_dispatch:\n  schedule:\n    - cron: \'43 6 * * sun\'\n\njobs:\n\n  sdist:\n    runs-on: ubuntu-latest\n\n    strategy:\n      fail-fast: false\n      matrix:\n        include:\n          - {package: psycopg_pool, format: sdist}\n          - {package: psycopg_pool, format: wheel}\n\n    steps:\n      - uses: actions/checkout@v5\n\n      - uses: actions/setup-python@v6\n        with:\n          python-version: "3.10"\n\n      - name: Install the build package\n        run: pip install build\n\n      - name: Create the package\n        run: python -m build -o dist --${{ matrix.format }} ${{ matrix.package }}\n\n      - name: Install the Python pool package and test requirements\n        run: pip install psycopg[test] dist/*\n\n      - name: Test the package\n        run: pytest -m \'pool and not slow and not flakey\' --color yes\n        env:\n          PSYCOPG_TEST_DSN: "host=127.0.0.1 user=postgres"\n          PGPASSWORD: password\n\n      - uses: actions/upload-artifact@v5\n        with:\n          name: ${{ matrix.package }}-${{ matrix.format }}\n          path: ./dist/*\n\n    services:\n      postgresql:\n        image: postgres:14\n        env:\n          POSTGRES_PASSWORD: password\n        ports:\n          - 5432:5432\n        # Set health checks to wait until postgres has started\n        options: >-\n          --health-cmd pg_isready\n          --health-interval 10s\n          --health-timeout 5s\n          --health-retries 5\n\n  merge:\n    runs-on: ubuntu-latest\n    needs:\n      - sdist\n    steps:\n      - name: Merge Artifacts\n        uses: actions/upload-artifact/merge@v5\n        with:\n          name: psycopg-pool-artifact\n          delete-merged: true\n',
            '.github/workflows/packages-src.yml': 'name: Build source packages\n\non:\n  push:\n    paths:\n      - \'.github/workflows/packages-src.yml\'\n  workflow_dispatch:\n  schedule:\n    - cron: \'37 6 * * sun\'\n\njobs:\n\n  sdist:\n    runs-on: ubuntu-latest\n    if: true\n\n    strategy:\n      fail-fast: false\n      matrix:\n        include:\n          - {package: psycopg, format: sdist, impl: python}\n          - {package: psycopg, format: wheel, impl: python}\n          - {package: psycopg_c, format: sdist, impl: c}\n\n    steps:\n      - uses: actions/checkout@v5\n\n      - uses: actions/setup-python@v6\n        with:\n          python-version: "3.10"\n\n      - name: Install the build package\n        run: pip install build\n\n      - name: Create the package\n        run: python -m build -o dist --${{ matrix.format }} ${{ matrix.package }}\n\n      - name: Install the Python package and test requirements\n        run: pip install `ls dist/*`[test] ./psycopg_pool\n        if: ${{ matrix.package == \'psycopg\' }}\n\n      - name: Install the C package and test requirements\n        run: pip install dist/* ./psycopg[test] ./psycopg_pool\n        if: ${{ matrix.package == \'psycopg_c\' }}\n\n      - name: Test the sdist package\n        run: pytest -m \'not slow and not flakey\' --color yes\n        env:\n          PSYCOPG_IMPL: ${{ matrix.impl }}\n          PSYCOPG_TEST_DSN: "host=127.0.0.1 user=postgres"\n          PGPASSWORD: password\n\n      - uses: actions/upload-artifact@v5\n        with:\n          name: ${{ matrix.package }}-${{ matrix.format }}-${{ matrix.impl }}\n          path: ./dist/*\n\n    services:\n      postgresql:\n        image: postgres:14\n        env:\n          POSTGRES_PASSWORD: password\n        ports:\n          - 5432:5432\n        # Set health checks to wait until postgres has started\n        options: >-\n          --health-cmd pg_isready\n          --health-interval 10s\n          --health-timeout 5s\n          --health-retries 5\n  merge:\n    runs-on: ubuntu-latest\n    needs:\n      - sdist\n    steps:\n      - name: Merge Artifacts\n        uses: actions/upload-artifact/merge@v5\n        with:\n          name: psycopg-src-artifact\n          delete-merged: true\n',
            '.github/workflows/tests.yml': 'name: Tests\n\non:\n  push:\n    # This should disable running the workflow on tags, according to the\n    # on.<push|pull_request>.<branches|tags> GitHub Actions docs.\n    branches:\n      - "**"\n    paths-ignore:\n      - README.rst\n      - "docs/*"\n  pull_request:\n  schedule:\n    - cron: \'48 6 * * *\'\n\nconcurrency:\n  # Cancel older requests of the same workflow in the same branch.\n  group: ${{ github.workflow }}-${{ github.ref_name }}\n  cancel-in-progress: true\n\njobs:\n\n  linux:  # {{{\n    runs-on: ubuntu-latest\n    if: true\n\n    strategy:\n      fail-fast: false\n      matrix:\n        include:\n          # Test different combinations of Python, Postgres, libpq.\n          - {impl: python, python: "3.10", postgres: "postgres:18", libpq: oldest}\n          - {impl: python, python: "3.11", postgres: "postgres:17", libpq: master}\n          - {impl: python, python: "3.12", postgres: "postgres:16", libpq: newest}\n          - {impl: python, python: "3.13", postgres: "postgres:13"}\n          - {impl: python, python: "3.14", postgres: "postgres:14"}\n          - {impl: python, python: "3.14t", postgres: "postgres:14"}\n\n          - {impl: c, python: "3.10", postgres: "postgres:13", libpq: master}\n          - {impl: c, python: "3.11", postgres: "postgres:15", libpq: oldest}\n          - {impl: c, python: "3.12", postgres: "postgres:16"}\n          - {impl: c, python: "3.13", postgres: "postgres:17", libpq: newest}\n          - {impl: c, python: "3.14", postgres: "postgres:18"}\n          - {impl: c, python: "3.14t", postgres: "postgres:18"}\n\n          - {impl: python, python: "3.10", ext: gevent, postgres: "postgres:17"}\n          - {impl: python, python: "3.10", ext: dns, postgres: "postgres:14"}\n          - {impl: python, python: "3.12", ext: postgis, postgres: "postgis/postgis"}\n          - {impl: python, python: "3.10", ext: numpy, postgres: "postgres:15"}\n          - {impl: c, python: "3.12", ext: numpy, postgres: "postgres:17"}\n          - {impl: c, python: "3.13", ext: gevent, postgres: "postgres:18"}\n\n          # Test with minimum dependencies versions\n          # WARNING: when bumping min version, make sure that the dependencies\n          # in tests/constraints.txt are updated and that binary packages\n          # are available for such version.\n          - {impl: c, python: "3.10", ext: min, postgres: "postgres:15"}\n\n          # Test memory alignment\n          - {impl: c, python: "3.12", ext: align, postgres: "postgres:17"}\n\n          # Test with PyPy.\n          - {impl: python, python: "pypy3.10", postgres: "postgres:14"}\n          - {impl: python, python: "pypy3.11", postgres: "postgres:15"}\n\n    env:\n      PSYCOPG_IMPL: ${{ matrix.impl }}\n      DEPS: ./psycopg[test] ./psycopg_pool\n      PSYCOPG_TEST_DSN: "host=127.0.0.1 user=postgres password=password"\n      MARKERS: ""\n\n    steps:\n      - uses: actions/checkout@v5\n\n      - uses: actions/setup-python@v6\n        with:\n          python-version: ${{ matrix.python }}\n          allow-prereleases: true\n\n      - name: Start PostgreSQL service\n        # Note: this would love to be a service, but I don\'t see a way to pass\n        # the args to the docker run command line.\n        run: |\n          docker pull ${{ matrix.postgres }}\n          docker run --rm -d --name postgres -p 5432:5432 \\\n            -e POSTGRES_PASSWORD=password ${{ matrix.postgres }} \\\n            -c max_prepared_transactions=10\n\n      - name: Install the wanted libpq version\n        run: sudo ./tools/ci/ci_install_libpq.sh ${{ matrix.libpq }}\n\n      - name: Include psycopg-c to the packages to install\n        if: ${{ matrix.impl == \'c\' }}\n        run: |\n          echo "DEPS=$DEPS ./psycopg_c" >> $GITHUB_ENV\n\n      - name: Include gevent to the packages to install\n        if: ${{ matrix.ext == \'gevent\' }}\n        run: |\n          echo "DEPS=$DEPS gevent" >> $GITHUB_ENV\n          echo "MARKERS=$MARKERS gevent" >> $GITHUB_ENV\n\n      - name: Include dnspython to the packages to install\n        if: ${{ matrix.ext == \'dns\' }}\n        run: |\n          echo "DEPS=$DEPS dnspython" >> $GITHUB_ENV\n          echo "MARKERS=$MARKERS dns" >> $GITHUB_ENV\n\n      - name: Include shapely to the packages to install\n        if: ${{ matrix.ext == \'postgis\' }}\n        run: |\n          echo "DEPS=$DEPS shapely" >> $GITHUB_ENV\n          echo "MARKERS=$MARKERS postgis" >> $GITHUB_ENV\n\n      - if: ${{ matrix.ext == \'numpy\' }}\n        run: |\n          echo "DEPS=$DEPS numpy" >> $GITHUB_ENV\n          echo "MARKERS=$MARKERS numpy" >> $GITHUB_ENV\n\n      - name: Exclude certain tests from pypy\n        if: ${{ startsWith(matrix.python, \'pypy\') }}\n        run: |\n          echo "NOT_MARKERS=$NOT_MARKERS timing mypy" >> $GITHUB_ENV\n\n      - name: Configure to use the oldest dependencies\n        if: ${{ matrix.ext == \'min\' }}\n        run: |\n          echo "DEPS=$DEPS dnspython shapely numpy gevent" >> $GITHUB_ENV\n          echo "PIP_CONSTRAINT=${{ github.workspace }}/tests/constraints.txt" \\\n            >> $GITHUB_ENV\n\n      - name: Configure memory alignment tests\n        if: ${{ matrix.ext == \'align\' }}\n        run: |\n          echo "CFLAGS=-fsanitize=undefined -Werror=strict-aliasing -Werror=odr -Werror=lto-type-mismatch"\n            >> $GITHUB_ENV\n          echo "UBSAN_OPTIONS=halt_on_error=1" >> $GITHUB_ENV\n          echo "PYTEST_ADDOPTS=-v" >> $GITHUB_ENV\n\n      - name: Install Python packages\n        run: pip install $DEPS\n\n      - name: Run tests\n        run: ./tools/ci/ci_test.sh\n\n\n  # }}}\n\n  pool-integration:  # {{{\n    # Test the current pool version with older psycopg versions\n    runs-on: ubuntu-latest\n    if: true\n\n    strategy:\n      fail-fast: false\n      matrix:\n        include:\n          - {psycopg: "3.3", python: "3.13", postgres: "postgres:17"}\n          - {psycopg: "3.2", python: "3.12", postgres: "postgres:17"}\n\n    env:\n      DEPS: psycopg<${{ matrix.psycopg }} ./psycopg_pool[test]\n      PSYCOPG_TEST_DSN: "host=127.0.0.1 user=postgres password=password"\n      MARKERS: "pool"\n\n    steps:\n      - uses: actions/checkout@v5\n\n      - uses: actions/setup-python@v6\n        with:\n          python-version: ${{ matrix.python }}\n\n      - name: Start PostgreSQL service\n        # Note: this would love to be a service, but I don\'t see a way to pass\n        # the args to the docker run command line.\n        run: |\n          docker pull ${{ matrix.postgres }}\n          docker run --rm -d --name postgres -p 5432:5432 \\\n            -e POSTGRES_PASSWORD=password ${{ matrix.postgres }} \\\n            -c max_prepared_transactions=10\n\n      - name: Install Python packages\n        run: pip install $DEPS\n\n      - name: Run tests\n        run: ./tools/ci/ci_test.sh\n\n\n  # }}}\n\n  macos-14:  # {{{\n    runs-on: macos-14\n    if: true\n\n    strategy:\n      fail-fast: false\n      matrix:\n        include:\n          - {impl: python, python: "3.10"}\n          - {impl: python, python: "3.11"}\n          - {impl: python, python: "3.12"}\n          - {impl: python, python: "3.13"}\n          - {impl: python, python: "3.14"}\n          - {impl: c, python: "3.10"}\n          - {impl: c, python: "3.11"}\n          - {impl: c, python: "3.12"}\n          - {impl: c, python: "3.13"}\n          - {impl: c, python: "3.14"}\n\n    env:\n      PSYCOPG_IMPL: ${{ matrix.impl }}\n      DEPS: ./psycopg[test] ./psycopg_pool\n      PSYCOPG_TEST_DSN: "host=127.0.0.1 user=runner dbname=postgres"\n      # MacOS on GitHub Actions seems particularly slow.\n      # Don\'t run timing-based tests as they regularly fail.\n      # pproxy-based tests fail too, with the proxy not coming up in 2s.\n      NOT_MARKERS: "timing proxy mypy"\n      PG_VERSION: "18"\n\n    steps:\n      - uses: actions/checkout@v5\n\n      - uses: actions/setup-python@v6\n        with:\n          python-version: ${{ matrix.python }}\n          allow-prereleases: true\n\n      - name: Install PostgreSQL on the runner\n        run: brew install postgresql@${PG_VERSION}\n\n      - name: Start PostgreSQL service\n        run: brew services start postgresql@${PG_VERSION}\n\n      - name: Find the libpq\n        if: ${{ matrix.impl == \'python\' }}\n        # NOTE: the libpq was found in:\n        # /opt/homebrew/opt/postgresql@${PG_VERSION}/lib before PG 17\n        # /opt/homebrew/opt/postgresql@${PG_VERSION}/lib/postgresql on PG 17\n        run: |\n          echo "DYLD_LIBRARY_PATH=/opt/homebrew/opt/postgresql@${PG_VERSION}/lib/postgresql:/opt/homebrew/opt/postgresql@${PG_VERSION}/lib:$DYLD_LIBRARY_PATH" \\\n              >> $GITHUB_ENV\n\n      - name: Include psycopg-c to the packages to install\n        if: ${{ matrix.impl == \'c\' }}\n        run: |\n          echo "DEPS=$DEPS ./psycopg_c" >> $GITHUB_ENV\n          echo "PATH=/opt/homebrew/opt/postgresql@${PG_VERSION}/bin:$PATH" >> $GITHUB_ENV\n\n      - name: Install Python packages\n        run: pip install $DEPS\n\n      - name: Run tests\n        run: ./tools/ci/ci_test.sh\n\n\n  # }}}\n\n  macos-13:  # {{{\n    runs-on: macos-13\n    if: true\n\n    strategy:\n      fail-fast: false\n      matrix:\n        include:\n          - {impl: python, python: "3.10"}\n          - {impl: c, python: "3.10"}\n\n    env:\n      PSYCOPG_IMPL: ${{ matrix.impl }}\n      DEPS: ./psycopg[test] ./psycopg_pool\n      PSYCOPG_TEST_DSN: "host=127.0.0.1 user=runner dbname=postgres"\n      # MacOS on GitHub Actions seems particularly slow.\n      # Don\'t run timing-based tests as they regularly fail.\n      # pproxy-based tests fail too, with the proxy not coming up in 2s.\n      NOT_MARKERS: "timing proxy mypy"\n      PG_VERSION: "17"\n\n    steps:\n      - uses: actions/checkout@v5\n\n      - uses: actions/setup-python@v6\n        with:\n          python-version: ${{ matrix.python }}\n\n      - name: Install PostgreSQL on the runner\n        run: brew install gnu-sed postgresql@${PG_VERSION}\n\n      - name: Start PostgreSQL service\n        run: brew services start postgresql@${PG_VERSION}\n\n      - name: Find the libpq\n        if: ${{ matrix.impl == \'python\' }}\n        run: |\n          echo "DYLD_LIBRARY_PATH=/usr/local/opt/postgresql@${PG_VERSION}/lib/postgresql:$DYLD_LIBRARY_PATH" \\\n              >> $GITHUB_ENV\n\n      - name: Include psycopg-c to the packages to install\n        if: ${{ matrix.impl == \'c\' }}\n        run: |\n          echo "DEPS=$DEPS ./psycopg_c" >> $GITHUB_ENV\n          echo "PATH=/usr/local/opt/postgresql@${PG_VERSION}/bin:$PATH" >> $GITHUB_ENV\n\n      - name: Install Python packages\n        run: pip install $DEPS\n\n      - name: Run tests\n        run: ./tools/ci/ci_test.sh\n\n\n  # }}}\n\n  windows:  # {{{\n    # TODO: move it back to windows-latest when the default runner switches.\n    runs-on: windows-2025\n    if: true\n\n    strategy:\n      fail-fast: false\n      matrix:\n        include:\n          - {impl: python, python: "3.10"}\n          - {impl: python, python: "3.11"}\n          - {impl: python, python: "3.12"}\n          - {impl: python, python: "3.13"}\n          - {impl: python, python: "3.14"}\n          - {impl: c, python: "3.10"}\n          - {impl: c, python: "3.11"}\n          - {impl: c, python: "3.12"}\n          - {impl: c, python: "3.13"}\n          - {impl: c, python: "3.14"}\n\n    env:\n      PSYCOPG_IMPL: ${{ matrix.impl }}\n      DEPS: ./psycopg[test] ./psycopg_pool\n      PSYCOPG_TEST_DSN: "host=127.0.0.1 dbname=postgres"\n      # On windows pproxy doesn\'t seem very happy. Also a few timing test fail.\n      NOT_MARKERS: "timing proxy mypy"\n\n    defaults:\n      run:\n        shell: bash\n\n    steps:\n      # there are some extra libpq.dll in PATH\n      - run: rm -rf c:/tools/php C:/Strawberry/c/bin\n\n      - uses: actions/checkout@v5\n\n      - uses: actions/setup-python@v6\n        with:\n          python-version: ${{ matrix.python }}\n          allow-prereleases: true\n\n      - name: Start PostgreSQL service\n        run: |\n          $PgSvc = Get-Service "postgresql*"\n          Set-Service $PgSvc.Name -StartupType manual\n          $PgSvc.Start()\n        shell: powershell\n\n      # Refcount tests are flakey on windows, often they fail with the likes of:\n      #\n      #   AssertionError: objects leaked: 0, -2\n      #\n      # Avoid the morning bother of a failed workflow.\n      - name: Exclude refcount tests in daily tests\n        if: ${{ github.event_name == \'schedule\' }}\n        run: echo "NOT_MARKERS=$NOT_MARKERS refcount" >> $GITHUB_ENV\n\n      - name: Export GitHub Actions cache environment variables\n      # https://learn.microsoft.com/en-us/vcpkg/consume/binary-caching-github-actions-cache\n        uses: actions/github-script@v8\n        with:\n          script: |\n            const path = require(\'path\')\n            core.exportVariable(\'ACTIONS_CACHE_URL\', process.env.ACTIONS_CACHE_URL || \'\');\n            core.exportVariable(\'ACTIONS_RUNTIME_TOKEN\', process.env.ACTIONS_RUNTIME_TOKEN || \'\');\n            core.addPath(path.join(process.env.VCPKG_INSTALLATION_ROOT, \'installed/x64-windows-release/lib\'));\n            core.addPath(path.join(process.env.VCPKG_INSTALLATION_ROOT, \'installed/x64-windows-release/bin\'));\n\n      - name: Install libpq from vcpkg and install pg_config.exe stub\n        run: .\\tools\\ci\\wheel_win32_before_build.bat\n        shell: powershell\n        env:\n          # cache vcpkg\n          VCPKG_BINARY_SOURCES: "clear;x-gha,readwrite"\n\n      - name: Build the C wheel\n        if: ${{ matrix.impl == \'c\' }}\n        run: |\n          # If the wheel is not delocated, import fails with some dll not found\n          # (but it won\'t tell which one).\n          pip wheel -v -w ./psycopg_c/dist/ ./psycopg_c/\n          delvewheel repair --no-mangle "libiconv-2.dll;libwinpthread-1.dll" \\\n            -w ./wheelhouse/ psycopg_c/dist/psycopg*.whl\n          echo "DEPS=$DEPS $(ls ./wheelhouse/*.whl)" >> $GITHUB_ENV\n\n      - name: Install Python packages\n        run: pip install $DEPS\n\n      - name: Run tests\n        run: ./tools/ci/ci_test.sh\n\n\n  # }}}\n\n  crdb:  # {{{\n    runs-on: ubuntu-latest\n    if: true\n\n    strategy:\n      fail-fast: false\n      matrix:\n        include:\n          # Releases: https://www.cockroachlabs.com/docs/releases/\n          # Images: https://console.cloud.google.com/artifacts/docker/cockroach-cloud-images/us/cockroachdb/cockroach\n          #\n          # Also useful:\n          #\n          #   curl -fsSL -X GET \\\n          #   https://us-docker.pkg.dev/v2/cockroach-cloud-images/cockroachdb/cockroach/tags/list \\\n          #   | jq .tags | egrep \'latest-[^-]+-build\' | sort\n          - {impl: c, crdb: "master", python: "3.13"}\n          - {impl: c, crdb: "v25.3", python: "3.13", libpq: newest}\n          - {impl: c, crdb: "v24.3", python: "3.10"}\n          - {impl: python, crdb: "v23.2", python: "3.12"}\n\n    env:\n      PSYCOPG_IMPL: ${{ matrix.impl }}\n      DEPS: ./psycopg[test] ./psycopg_pool\n      PSYCOPG_TEST_DSN: "host=127.0.0.1 port=26257 user=root dbname=defaultdb"\n      CRDB_REPO: us-docker.pkg.dev/cockroach-cloud-images/cockroachdb/cockroach\n      # Since CRDB 25.1, \'on\' should become the default, which will break\n      # the test suite assumption.\n      # https://www.cockroachlabs.com/docs/stable/online-schema-changes#enable-automatic-commit-before-running-schema-changes-inside-transactions\n      PGOPTIONS: "-c autocommit_before_ddl=off"\n\n    steps:\n      - uses: actions/checkout@v5\n\n      - uses: actions/setup-python@v6\n        with:\n          python-version: ${{ matrix.python }}\n\n      - name: Start CockroachDB service\n        # Note: this would love to be a service, but I don\'t see a way to pass\n        # the args to the docker run command line.\n        run: |\n          if [[ ${{ matrix.crdb }} == "master" ]]; then\n            image=us-docker.pkg.dev/cockroach-cloud-images/cockroachdb/cockroach:latest-master-build\n          else\n            image=cockroachdb/cockroach:latest-${{ matrix.crdb }}\n          fi\n          docker pull ${image}\n          docker run --rm -d --name crdb -p 26257:26257 ${image} \\\n            start-single-node --insecure\n\n      - name: Install the wanted libpq version\n        run: sudo ./tools/ci/ci_install_libpq.sh ${{ matrix.libpq }}\n\n      - name: Include psycopg-c to the packages to install\n        if: ${{ matrix.impl == \'c\' }}\n        run: |\n          echo "DEPS=$DEPS ./psycopg_c" >> $GITHUB_ENV\n\n      - name: Install Python packages\n        run: pip install $DEPS\n\n      - name: Run tests\n        run: ./tools/ci/ci_test.sh\n\n\n  # }}}\n',
        }
